index.styles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif;
      color: #333;
      line-height: 1.8;
      background: #feffff;
    }

    .hero {
      background: #333;
      color: #feffff;
      padding: 100px 20px;
      text-align: center;
      position: relative;
      overflow: hidden;
    }
    .hero::before {
      content: '';
      position: absolute;
      top: 0; left: 0; right: 0; bottom: 0;
      background: linear-gradient(135deg, rgba(21,183,136,0.15) 0%, transparent 50%, rgba(19,149,186,0.1) 100%);
    }
    .hero-inner { position: relative; max-width: 720px; margin: 0 auto; }
    .hero h1 { font-size: 2.8rem; font-weight: 800; margin-bottom: 0.3rem; letter-spacing: -0.02em; }
    .hero h1 small { font-size: 1.2rem; font-weight: 400; display: block; color: #15b788; margin-top: 0.2rem; }
    .hero .eyebrow {
      display: inline-block;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(255,255,255,0.2);
      border-radius: 100px;
      padding: 6px 18px;
      font-size: 0.8rem;
      letter-spacing: 0.05em;
      margin-bottom: 1.5rem;
      color: #15b788;
    }
    .hero .cost-visual {
      display: flex;
      justify-content: center;
      gap: 24px;
      margin: 2rem 0;
      flex-wrap: wrap;
    }
    .hero .cost-card {
      background: rgba(255,255,255,0.06);
      border: 1px solid rgba(255,255,255,0.12);
      border-radius: 12px;
      padding: 18px 24px;
      min-width: 140px;
    }
    .hero .cost-card .label { font-size: 0.75rem; opacity: 0.7; margin-bottom: 4px; }
    .hero .cost-card .amount { font-size: 1.5rem; font-weight: 700; color: #15b788; }
    .hero .cost-card .amount .unit { font-size: 0.9rem; font-weight: 400; }
    .hero .cost-total {
      margin-top: 0.5rem;
      font-size: 1rem;
      color: rgba(255,255,255,0.8);
    }
    .hero .cost-total strong { color: #fff; }

    section { padding: 80px 20px; }
    section:nth-child(even) { background: #f8f9fa; }
    .container { max-width: 800px; margin: 0 auto; }

    .section-title {
      font-size: 1.6rem;
      font-weight: 700;
      text-align: center;
      margin-bottom: 0.5rem;
    }
    .section-subtitle {
      text-align: center;
      color: #888;
      font-size: 0.95rem;
      margin-bottom: 3rem;
    }

    .insight-card {
      background: #fff;
      border-radius: 16px;
      padding: 32px;
      border: 1px solid #eee;
      box-shadow: 0 2px 8px rgba(0,0,0,0.04);
      margin-bottom: 20px;
    }
    .insight-card h3 {
      font-size: 1.1rem;
      color: #1395ba;
      margin-bottom: 0.8rem;
    }
    .insight-card p { font-size: 0.95rem; color: #555; }
    .insight-card .big-number {
      font-size: 2.5rem;
      font-weight: 800;
      color: #333;
      line-height: 1.2;
    }
    .insight-card .big-number .currency { font-size: 1.2rem; color: #15b788; }

    .features-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
      gap: 20px;
    }
    .feature-card {
      background: #fff;
      border-radius: 12px;
      padding: 28px;
      border: 1px solid #eee;
      transition: transform 0.2s, box-shadow 0.2s;
    }
    .feature-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 16px rgba(0,0,0,0.06);
    }
    .feature-card .icon { font-size: 2rem; margin-bottom: 0.8rem; }
    .feature-card h3 { font-size: 1rem; color: #333; margin-bottom: 0.5rem; }
    .feature-card p { font-size: 0.85rem; color: #666; line-height: 1.6; }

    .pricing-grid {
      display: flex;
      justify-content: center;
      gap: 20px;
      flex-wrap: wrap;
    }
    .pricing-card {
      background: #fff;
      border-radius: 16px;
      padding: 32px;
      width: 280px;
      border: 2px solid #eee;
      text-align: center;
    }
    .pricing-card.featured {
      border-color: #15b788;
      box-shadow: 0 4px 20px rgba(21,183,136,0.12);
    }
    .pricing-card .plan-name { font-size: 1rem; font-weight: 700; margin-bottom: 0.3rem; }
    .pricing-card .plan-price { font-size: 2.2rem; font-weight: 800; color: #333; margin: 1rem 0; }
    .pricing-card .plan-price .unit { font-size: 0.9rem; font-weight: 400; color: #888; }
    .pricing-card .plan-desc { font-size: 0.85rem; color: #666; margin-bottom: 1.5rem; }
    .pricing-card .plan-features { text-align: left; list-style: none; }
    .pricing-card .plan-features li {
      font-size: 0.85rem;
      padding: 6px 0;
      border-bottom: 1px solid #f0f0f0;
      position: relative;
      padding-left: 20px;
    }
    .pricing-card .plan-features li::before { content: '✓'; position: absolute; left: 0; color: #15b788; font-weight: 700; }
    .pricing-card .plan-label {
      display: inline-block;
      background: #15b788;
      color: #fff;
      font-size: 0.75rem;
      padding: 2px 12px;
      border-radius: 100px;
      font-weight: 600;
    }

    .cta-section { text-align: center; padding: 80px 20px; }
    .cta-section p { font-size: 1.1rem; margin-bottom: 1.5rem; color: #555; }
    .cta-section .btn {
      display: inline-block;
      background: #15b788;
      color: #fff;
      text-decoration: none;
      padding: 16px 40px;
      border-radius: 10px;
      font-size: 1.05rem;
      font-weight: 700;
      transition: background 0.2s;
    }
    .cta-section .btn:hover { background: #12a077; }
    .cta-section .btn.secondary { background: #1395ba; margin-left: 12px; }
    .cta-section .btn.secondary:hover { background: #107a99; }
    .cta-section .micro { margin-top: 1rem; font-size: 0.8rem; color: #999; }
    .cta-section .store-badges {
      display: flex;
      justify-content: center;
      gap: 16px;
      margin-top: 1.5rem;
      flex-wrap: wrap;
    }
    .cta-section .store-badge {
      display: inline-block;
      background: #333;
      color: #fff;
      padding: 12px 24px;
      border-radius: 8px;
      font-size: 0.9rem;
      font-weight: 600;
      text-decoration: none;
      transition: background 0.2s, transform 0.15s;
    }
    .cta-section .store-badge:hover {
      background: #111;
      transform: translateY(-1px);
    }

    footer {
      text-align: center;
      padding: 32px 20px;
      border-top: 1px solid #eee;
      font-size: 0.85rem;
      color: #888;
    }
    footer a { color: #1395ba; text-decoration: none; }
    footer a:hover { text-decoration: underline; }
    footer .links { margin-bottom: 0.5rem; }
    footer .links a { margin: 0 12px; }

    @media (max-width: 640px) {
      .hero h1 { font-size: 2rem; }
      .hero .cost-visual { gap: 12px; }
      .hero .cost-card { padding: 14px 18px; min-width: 100px; }
      .hero .cost-card .amount { font-size: 1.2rem; }
      .insight-card .big-number { font-size: 1.8rem; }
      .pricing-card { width: 100%; max-width: 320px; }
      .cta-section .btn.secondary { margin-left: 0; margin-top: 12px; }
    }

    .screenshot-gallery {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
      gap: 20px;
      margin-top: 2rem;
    }
    .screenshot-item {
      border-radius: 12px;
      overflow: hidden;
      box-shadow: 0 2px 12px rgba(0,0,0,0.08);
      transition: transform 0.2s, box-shadow 0.2s;
      background: #fff;
    }
    .screenshot-item:hover {
      transform: translateY(-3px);
      box-shadow: 0 6px 24px rgba(0,0,0,0.12);
    }
    .screenshot-item img { width: 100%; height: auto; display: block; }
    .screenshot-label {
      display: block;
      padding: 12px 16px;
      font-size: 0.85rem;
      color: #555;
      text-align: center;
      font-weight: 600;
    }

